#!/usr/bin/env python
"""Generate .github/workflows/ci.yml from the CI policy manifests in .mise/ci/.

The CI target support policy lives in declarative manifests:

- variants/*.toml        one file per CI target (mise_env + GH Actions runner)
- steps.toml             variant-job steps with declarative applicability rules
- workflow.template.yml  static workflow structure around the generated blocks

`mise run ci:generate-workflow` rewrites the checked-in workflow, and
`mise run ci:generate-workflow -- --check` fails without writing when the
checked-in workflow has drifted from the manifests.
"""

import argparse
import difflib
import sys
import tomllib
from dataclasses import dataclass
from pathlib import Path
from typing import Any

REPO_ROOT = Path(__file__).resolve().parents[2]
MISE_DIR = REPO_ROOT / ".mise"
CI_DIR = MISE_DIR / "ci"
WORKFLOW_PATH = REPO_ROOT / ".github" / "workflows" / "ci.yml"

MATRIX_MARKER = "# @generated:variant-matrix"
STEPS_MARKER = "# @generated:variant-steps"

VARIANT_KEYS = {"mise_env", "runner"}
STEP_KEYS = {
    "name",
    "run",
    "comments",
    "skip_variants",
    "only_variants",
    "skip_prefixes",
    "only_prefixes",
    "contains",
}


class PolicyError(Exception):
    """Raised when the CI policy manifests are invalid or inconsistent."""


@dataclass(frozen=True)
class Variant:
    mise_env: str
    runner: str


@dataclass(frozen=True)
class Step:
    run: str
    name: str | None = None
    comments: tuple[str, ...] = ()
    skip_variants: tuple[str, ...] = ()
    only_variants: tuple[str, ...] = ()
    skip_prefixes: tuple[str, ...] = ()
    only_prefixes: tuple[str, ...] = ()
    contains: tuple[str, ...] = ()


def _require_str(data: dict[str, Any], key: str, context: str) -> str:
    value = data.get(key)
    if not isinstance(value, str) or not value:
        raise PolicyError(f"{context}: '{key}' must be a non-empty string")
    return value


def _str_tuple(data: dict[str, Any], key: str, context: str) -> tuple[str, ...]:
    value = data.get(key, [])
    if not isinstance(value, list) or not all(isinstance(v, str) for v in value):
        raise PolicyError(f"{context}: '{key}' must be a list of strings")
    return tuple(value)


def load_variants(ci_dir: Path) -> list[Variant]:
    variants_dir = ci_dir / "variants"
    paths = sorted(variants_dir.glob("*.toml"))
    if not paths:
        raise PolicyError(f"no variant manifests found in {variants_dir}")
    variants: list[Variant] = []
    for path in paths:
        context = str(path)
        data = tomllib.loads(path.read_text(encoding="utf-8"))
        unknown = set(data) - VARIANT_KEYS
        if unknown:
            raise PolicyError(f"{context}: unknown keys {sorted(unknown)}")
        mise_env = _require_str(data, "mise_env", context)
        if path.stem != mise_env:
            raise PolicyError(
                f"{context}: mise_env '{mise_env}' must match the file name"
            )
        variants.append(
            Variant(mise_env=mise_env, runner=_require_str(data, "runner", context))
        )
    variants.sort(key=lambda variant: variant.mise_env)
    return variants


def load_steps(ci_dir: Path) -> list[Step]:
    path = ci_dir / "steps.toml"
    data = tomllib.loads(path.read_text(encoding="utf-8"))
    raw_steps = data.get("steps")
    if not isinstance(raw_steps, list) or not raw_steps:
        raise PolicyError(f"{path}: expected at least one [[steps]] entry")
    steps: list[Step] = []
    for index, raw in enumerate(raw_steps):
        context = f"{path}: [[steps]] #{index + 1}"
        if not isinstance(raw, dict):
            raise PolicyError(f"{context}: must be a table")
        unknown = set(raw) - STEP_KEYS
        if unknown:
            raise PolicyError(f"{context}: unknown keys {sorted(unknown)}")
        name = raw.get("name")
        if name is not None and not isinstance(name, str):
            raise PolicyError(f"{context}: 'name' must be a string")
        steps.append(
            Step(
                run=_require_str(raw, "run", context),
                name=name,
                comments=_str_tuple(raw, "comments", context),
                skip_variants=_str_tuple(raw, "skip_variants", context),
                only_variants=_str_tuple(raw, "only_variants", context),
                skip_prefixes=_str_tuple(raw, "skip_prefixes", context),
                only_prefixes=_str_tuple(raw, "only_prefixes", context),
                contains=_str_tuple(raw, "contains", context),
            )
        )
    return steps


def applies_to(step: Step, mise_env: str) -> bool:
    if mise_env in step.skip_variants:
        return False
    if step.only_variants and mise_env not in step.only_variants:
        return False
    if any(mise_env.startswith(prefix) for prefix in step.skip_prefixes):
        return False
    if step.only_prefixes and not any(
        mise_env.startswith(prefix) for prefix in step.only_prefixes
    ):
        return False
    return all(part in mise_env for part in step.contains)


def validate(
    variants: list[Variant], steps: list[Step], config_envs: set[str]
) -> None:
    known = [variant.mise_env for variant in variants]
    known_set = set(known)
    if len(known) != len(known_set):
        raise PolicyError("duplicate variant manifests")

    missing = sorted(config_envs - known_set)
    extra = sorted(known_set - config_envs)
    if missing or extra:
        details = []
        if missing:
            details.append(f"missing manifests for {missing}")
        if extra:
            details.append(f"manifests without .mise/config.*.toml for {extra}")
        raise PolicyError(
            "CI variants must match the .mise/config.*.toml variants: "
            + "; ".join(details)
        )

    for step in steps:
        label = step.name or step.run
        for env in (*step.skip_variants, *step.only_variants):
            if env not in known_set:
                raise PolicyError(f"step '{label}': unknown variant '{env}'")
        for prefix in (*step.skip_prefixes, *step.only_prefixes):
            if not any(env.startswith(prefix) for env in known):
                raise PolicyError(
                    f"step '{label}': prefix '{prefix}' matches no variant"
                )
        for part in step.contains:
            if not any(part in env for env in known):
                raise PolicyError(
                    f"step '{label}': '{part}' is contained in no variant"
                )
        if not any(applies_to(step, env) for env in known):
            raise PolicyError(f"step '{label}': its rules exclude every variant")


def render_condition(step: Step) -> str | None:
    parts = [f"matrix.mise_env != '{env}'" for env in step.skip_variants]
    if step.only_variants:
        parts.append(
            " || ".join(f"matrix.mise_env == '{env}'" for env in step.only_variants)
        )
    parts += [
        f"!startsWith(matrix.mise_env, '{prefix}')" for prefix in step.skip_prefixes
    ]
    parts += [
        f"startsWith(matrix.mise_env, '{prefix}')" for prefix in step.only_prefixes
    ]
    parts += [f"contains(matrix.mise_env, '{part}')" for part in step.contains]
    return " && ".join(parts) if parts else None


def render_matrix(variants: list[Variant]) -> list[str]:
    lines: list[str] = []
    for variant in variants:
        lines.append(f"          - mise_env: {variant.mise_env}")
        lines.append(f"            runner: {variant.runner}")
    return lines


def render_steps(steps: list[Step]) -> list[str]:
    lines: list[str] = []
    for step in steps:
        lines += [f"      # {comment}" for comment in step.comments]
        condition = render_condition(step)
        if step.name is not None:
            lines.append(f"      - name: {step.name}")
            if condition is not None:
                lines.append(f"        if: ${{{{ {condition} }}}}")
            lines.append(f"        run: {step.run}")
        else:
            lines.append(f"      - run: {step.run}")
            if condition is not None:
                lines.append(f"        if: ${{{{ {condition} }}}}")
    return lines


def render_workflow(ci_dir: Path, mise_dir: Path) -> str:
    variants = load_variants(ci_dir)
    steps = load_steps(ci_dir)
    config_envs = {
        path.stem.removeprefix("config.")
        for path in mise_dir.glob("config.*.toml")
    }
    validate(variants, steps, config_envs)

    template = (ci_dir / "workflow.template.yml").read_text(encoding="utf-8")
    lines: list[str] = []
    for line in template.splitlines():
        marker = line.strip()
        if marker == MATRIX_MARKER:
            lines += render_matrix(variants)
        elif marker == STEPS_MARKER:
            lines += render_steps(steps)
        else:
            lines.append(line)
    return "\n".join(lines) + "\n"


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--check",
        action="store_true",
        help="fail if the checked-in workflow has drifted, without rewriting it",
    )
    args = parser.parse_args(argv)

    try:
        rendered = render_workflow(CI_DIR, MISE_DIR)
    except PolicyError as error:
        print(f"ci:generate-workflow: {error}", file=sys.stderr)
        return 2

    if args.check:
        current = (
            WORKFLOW_PATH.read_text(encoding="utf-8")
            if WORKFLOW_PATH.exists()
            else ""
        )
        if current != rendered:
            print(
                f"{WORKFLOW_PATH.relative_to(REPO_ROOT)} is out of sync with the "
                "manifests in .mise/ci/; run `mise run ci:generate-workflow`",
                file=sys.stderr,
            )
            diff = difflib.unified_diff(
                current.splitlines(keepends=True),
                rendered.splitlines(keepends=True),
                fromfile="checked-in",
                tofile="generated",
            )
            sys.stdout.writelines(diff)
            return 1
        print(
            f"{WORKFLOW_PATH.relative_to(REPO_ROOT)} is in sync with .mise/ci/"
        )
        return 0

    WORKFLOW_PATH.write_text(rendered, encoding="utf-8")
    print(f"wrote {WORKFLOW_PATH.relative_to(REPO_ROOT)}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

